parameters.jsCode:
const resp = $input.first().json;
const script = JSON.parse(resp.choices[0].message.content);
const prev = $('Parse Topic').first().json;

// Build SamAutomation scenes with built-in AI image generation
// No external Pollinations needed — SamAutomation generates images via Flux
const scenes = script.scenes.map((scene, i) => {
  return {
    "elements": [
      {
        "type": "image",
        "model": "flux-pro",
        "prompt": scene.description + ', photorealistic, cinematic lighting, 8K, vertical 9:16, no text, vivid colors',
        "aspect-ratio": "vertical",
        "resize": "cover",
        "zoom": 5,
        "duration": -1
      },
      {
        "type": "voice",
        "text": scene.narration || script.clean_script.split('.').slice(i, i+2).join('.'),
        "voice": prev.voice_id || "en-US-ChristopherNeural"
      }
    ]
  };
});

// Build full SamAutomation render payload
const payload = {
  "comment": script.youtube_title || prev.topic_title,
  "resolution": "custom",
  "width": 1080,
  "height": 1920,
  "quality": "high",
  "scenes": scenes,
  "elements": [
    {
      "type": "subtitles",
      "settings": {
        "type": "word",
        "position": "bottom-center",
        "font-family": "Montserrat",
        "font-weight": "800",
        "font-size": "8vw",
        "font-color": "#FFFFFF",
        "outline-color": "#000000",
        "outline-width": 3,
        "margin-bottom": "15vh"
      }
    }
  ]
};

return [{ json: {
  render_payload: payload,
  youtube_title: script.youtube_title,
  youtube_description: script.youtube_description,
  tags: script.tags,
  hashtags: script.hashtags,
  topic_title: prev.topic_title,
  selected_niche: prev.selected_niche
}}];

const status = $input.first().json;
const meta = $('Build Video Payload').first().json;

return [{ json: {
  video_url: status.url,
  video_duration: status.duration,
  youtube_title: meta.youtube_title,
  youtube_description: meta.youtube_description,
  tags: meta.tags,
  hashtags: meta.hashtags,
  topic_title: meta.topic_title,
  selected_niche: meta.selected_niche
}}];
